import React from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css"; // Import styles

const Navbar = () => {
  const sections = [
    { name: "HOME", id: "home" },
    { name: "ABOUT US", id: "about-us" },
    { name: "AREAS OF PRACTICE", id: "areas-of-practice" },
    { name: "OUR PROFESSIONALS", id: "our-professionals" },
    { name: "NEWS & ARTICLES", id: "news-articles" },
    { name: "GALLERY", id: "gallery" },
    { name: "CONTACT US", id: "contact" }, // Fix the typo from COUNTACT US to CONTACT US
  ];

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <Link to="home" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </Link>
      </div>
      <ul className="navbar-links">
        {sections.map(({ name, id }) => (
          <li key={id}>
            <Link 
              to={id} 
              smooth={true} 
              duration={500} 
              activeClass="active"
              spy={true} // Adds active class when in view
              offset={-70} // Adjust for navbar height
            >
              {name}
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
